query ContentRankingPage($limit: Int!, $offset: Int!, $filter: PPVContentRankingFilterInput, $isAmateur: Boolean = false, $isAnime: Boolean = false, $isLoggedIn: Boolean = false, $shouldGetBookmark: Boolean!) {
  ppvContentRanking(limit: $limit, offset: $offset, filter: $filter) {
    items {
      id
      rank
      content {
        title
        releaseStatus
        packageImage {
          mediumUrl
          largeUrl
          __typename
        }
        wishlistCount
        isExclusiveDelivery
        contentType
        utilizationStatus @include(if: $isLoggedIn)
        isInWishList @include(if: $shouldGetBookmark)
        pricing {
          sale {
            id
            name
            endAt
            __typename
          }
          productPricing {
            id
            priority
            regularPriceInclusiveTax
            __typename
          }
          lowestEffectivePriceInclusiveTax
          lowestRegularPriceInclusiveTax
          hasMultiplePrices
          __typename
        }
        actresses @skip(if: $isAmateur) {
          id
          name
          __typename
        }
        amateurActress @include(if: $isAmateur) {
          id
          name
          bustCup
          bust
          waist
          hip
          __typename
        }
        maker @include(if: $isAnime) {
          id
          name
          __typename
        }
        sampleImages {
          number
          largeImageUrl
          __typename
        }
        hasSampleMovie
        review {
          average
          total
          __typename
        }
        __typename
      }
      __typename
    }
    ... on PPVContentTrendingRanking {
      targetWindowEndAt
      __typename
    }
    __typename
  }
}
